{
  "name": "chyren-web",
  "version": "0.1.0",
  "private": true,
  "engines": {
    "node": ">=20 <25"
  },
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint"
  },
  "dependencies": {
    "react": "^18.2.0",
    "react-dom": "^18.2.0",
    "next": "^15.0.0",
    "axios": "^1.7.0",
    "tailwindcss": "^3.4.0"
  },
  "devDependencies": {
    "@types/node": "^20.0.0",
    "@types/react": "^18.2.0",
    "typescript": "^5.3.0",
    "postcss": "^8.4.0",
    "autoprefixer": "^10.4.0"
  }
}

import type { NextConfig } from 'next'
import path from 'node:path'

/** Public API base baked into the client bundle at build time. */
function publicApiBaseUrl(): string {
  if (process.env.NEXT_PUBLIC_API_BASE_URL) {
    return process.env.NEXT_PUBLIC_API_BASE_URL
  }
  // Vercel sets VERCEL_URL (hostname only) during build — same-origin API routes work.
  if (process.env.VERCEL_URL) {
    return `https://${process.env.VERCEL_URL}`
  }
  return 'http://localhost:8080'
}

const nextConfig: NextConfig = {
  // Docker/self-host uses standalone; Vercel uses its own Next runtime
  ...(process.env.VERCEL ? {} : { output: 'standalone' as const }),
  // Avoid tracing the wrong workspace when other lockfiles exist under $HOME
  outputFileTracingRoot: path.join(process.cwd()),
  reactStrictMode: true,
  typescript: {
    tsconfigPath: './tsconfig.json',
  },
  env: {
    NEXT_PUBLIC_API_BASE_URL: publicApiBaseUrl(),
  },
}

export default nextConfig

import type { Metadata } from 'next'
import './globals.css'

export const metadata: Metadata = {
  title: 'Chyren — Sovereign Intelligence',
  description: 'Chyren: The sovereign intelligence orchestrator',
}

export default function RootLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <html lang="en">
      <body className="bg-chyren-900 text-white">
        <div className="min-h-screen flex flex-col">
          <header className="bg-black border-b border-chyren-500 py-4 px-6">
            <h1 className="text-3xl font-bold text-chyren-500">⚡ CHYREN</h1>
            <p className="text-chyren-100 text-sm mt-1">Sovereign Intelligence Orchestrator</p>
          </header>
          <main className="flex-1 container mx-auto px-6 py-8">
            {children}
          </main>
          <footer className="border-t border-chyren-500 py-4 px-6 text-center text-chyren-100 text-sm">
            <p>© 2026 Chyren Sovereign Intelligence. All policy enforced.</p>
          </footer>
        </div>
      </body>
    </html>
  )
}

