export interface OmegaRuntimeMetadata {
  omegaStack?: string;
  omegaOutcome?: string;
  omegaMode?: string;
  omegaCorpusClass?: string;
  omegaEnvelopeVersion?: string;
  omegaPhylacteryHead?: string;
  omegaRiskScore?: string;
  provider?: string;
  providerAttempts?: string;
  sessionId?: string;
  memoryBackend?: string;
}

export function extractOmegaRuntimeMetadata(headers: Headers): OmegaRuntimeMetadata {
  return {
    omegaStack: headers.get('X-Omega-Stack') || undefined,
    omegaOutcome: headers.get('X-Omega-Outcome') || undefined,
    omegaMode: headers.get('X-Omega-Mode') || undefined,
    omegaCorpusClass: headers.get('X-Omega-Corpus-Class') || undefined,
    omegaEnvelopeVersion: headers.get('X-Omega-Envelope-Version') || undefined,
    omegaPhylacteryHead: headers.get('X-Omega-Phylactery-Head') || undefined,
    omegaRiskScore: headers.get('X-Omega-Risk-Score') || undefined,
    provider: headers.get('X-Provider') || undefined,
    providerAttempts: headers.get('X-Provider-Attempts') || undefined,
    sessionId: headers.get('X-Session-Id') || undefined,
    memoryBackend: headers.get('X-Memory-Backend') || undefined,
  };
}

export async function chat(req: ChatRequest): Promise<ChatResponse> {
  const res = await fetch('/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(req),
  });

  if (!res.ok) {
    const body = await res.json().catch(() => ({ error: res.statusText }));
    throw new Error((body as { error?: string }).error ?? `${res.status}`);
  }

  return res.json() as Promise<ChatResponse>;
}

export async function chatStream(
  req: ChatRequest, 
  onChunk: (text: string) => void,
  onStatus?: (text: string) => void
): Promise<OmegaRuntimeMetadata> {
  const res = await fetch('/api/chat', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(req),
  });

  if (!res.ok) {
    const body = await res.json().catch(() => ({ error: res.statusText }));
    throw new Error((body as { error?: string }).error ?? `${res.status}`);
  }

  const metadata = extractOmegaRuntimeMetadata(res.headers);

  if (!res.body) throw new Error("No response body");

  const reader = res.body.getReader();
  const decoder = new TextDecoder();
  let buffer = "";

  while (true) {
    const { value, done } = await reader.read();
    if (done) break;
    const chunkText = decoder.decode(value, { stream: true });
    buffer += chunkText;

    // Split by SSE double newline if it looks like status events are active
    while (buffer.includes('\n\n')) {
      const idx = buffer.indexOf('\n\n');
      const line = buffer.slice(0, idx).trim();
      if (line.startsWith('data: {"type":"status"')) {
        try {
          const json = JSON.parse(line.slice(5));
          if (onStatus) onStatus(json.text);
          buffer = buffer.slice(idx + 2);
          continue;
        } catch {
          // fallback if parse fails
        }
      }
      break; // stop if front of buffer isn't a status event
    }

    if (buffer && !buffer.startsWith('data: {"type":"status"')) {
      onChunk(buffer);
      buffer = "";
    }
  }

  // Flush remaining buffer
  const final = decoder.decode();
  buffer += final;
  if (buffer) onChunk(buffer);

  return metadata;
}

