1	'use client';
2	
3	import { useCallback, useEffect, useRef, useState } from 'react';
4	
5	export interface Message {
6	  id: string;
7	  role: 'user' | 'assistant';
8	  content: string;
9	  timestamp: number;
10	  status?: 'streaming' | 'done' | 'error';
11	}
12	
13	export interface Conversation {
14	  id: string;
15	  title: string;
16	  messages: Message[];
17	  createdAt: number;
18	}
19	
20	export interface SystemState {
21	  provider: string;
22	  model: string;
23	  status: 'online' | 'degraded' | 'offline';
24	  memoryEntries: number;
25	  mode: 'public' | 'operator';
26	  uptime?: string;
27	}
28	
29	export interface TelemetryEntry {
30	  id: string;
31	  timestamp: number;
32	  type: string;
33	  label: string;
34	  value: string | number;
35	}
36	
37	function uid(): string {
38	  return Math.random().toString(36).slice(2) + Date.now().toString(36);
39	}
40	
41	function deriveTitle(text: string): string {
42	  return text.slice(0, 40) + (text.length > 40 ? '…' : '');
43	}
44	
45	const DEFAULT_SYSTEM_STATE: SystemState = {
46	  provider: 'OmegA',
47	  model: 'sovereign',
48	  status: 'online',
49	  memoryEntries: 0,
50	  mode: 'public',
51	};
52	
53	export function useOmegaChat() {
54	  const [conversations, setConversations] = useState<Conversation[]>(() => {
55	    const first: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
56	    return [first];
57	  });
58	  const [activeConvoId, setActiveConvoId] = useState<string>(() => '');
59	  const [isStreaming, setIsStreaming] = useState(false);
60	  const [systemState, setSystemState] = useState<SystemState>(DEFAULT_SYSTEM_STATE);
61	  const [telemetry, setTelemetry] = useState<TelemetryEntry[]>([]);
62	  const abortRef = useRef<AbortController | null>(null);
63	
64	  // init activeConvoId from first conversation
65	  useEffect(() => {
66	    setActiveConvoId(prev => prev || conversations[0]?.id || '');
67	  }, []);
68	
69	  const activeConvo = conversations.find(c => c.id === activeConvoId);
70	
71	  const addTelemetry = useCallback((type: string, label: string, value: string | number) => {
72	    const entry: TelemetryEntry = { id: uid(), timestamp: Date.now(), type, label, value };
73	    setTelemetry(prev => [entry, ...prev].slice(0, 100));
74	  }, []);
75	
76	  // Poll runtime status every 30s
77	  useEffect(() => {
78	    const poll = async () => {
79	      try {
80	        const res = await fetch('/api/runtime-status');
81	        if (!res.ok) return;
82	        const data = await res.json();
83	        setSystemState(prev => ({
84	          ...prev,
85	          provider: data.posture?.provider ?? data.app ?? prev.provider,
86	          model: data.posture?.model ?? prev.model,
87	          status: data.posture?.status === 'degraded' ? 'degraded' : 'online',
88	          memoryEntries: data.posture?.memoryEntries ?? prev.memoryEntries,
89	          mode: data.posture?.mode ?? prev.mode,
90	          uptime: data.deployment?.vercelEnv ?? prev.uptime,
91	        }));
92	      } catch {
93	        setSystemState(prev => ({ ...prev, status: 'degraded' }));
94	      }
95	    };
96	    poll();
97	    const interval = setInterval(poll, 30_000);
98	    return () => clearInterval(interval);
99	  }, []);
100	
101	  const newConversation = useCallback(() => {
102	    const convo: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
103	    setConversations(prev => [convo, ...prev]);
104	    setActiveConvoId(convo.id);
105	  }, []);
106	
107	  const switchConversation = useCallback((id: string) => {
108	    setActiveConvoId(id);
109	  }, []);
110	
111	  const deleteConversation = useCallback((id: string) => {
112	    setConversations(prev => {
113	      const next = prev.filter(c => c.id !== id);
114	      if (next.length === 0) {
115	        const fresh: Conversation = { id: uid(), title: 'New conversation', messages: [], createdAt: Date.now() };
116	        return [fresh];
117	      }
118	      return next;
119	    });
120	    setActiveConvoId(prev => {
121	      if (prev !== id) return prev;
122	      const remaining = conversations.filter(c => c.id !== id);
123	      return remaining[0]?.id ?? '';
124	    });
125	  }, [conversations]);
126	
127	  const sendMessage = useCallback(async (text: string) => {
128	    if (!text.trim() || isStreaming) return;
129	
130	    const userMsg: Message = { id: uid(), role: 'user', content: text.trim(), timestamp: Date.now(), status: 'done' };
131	    const assistantMsgId = uid();
132	    const assistantMsg: Message = { id: assistantMsgId, role: 'assistant', content: '', timestamp: Date.now(), status: 'streaming' };
133	
134	    setConversations(prev => prev.map(c => {
135	      if (c.id !== activeConvoId) return c;
136	      const msgs = [...c.messages, userMsg, assistantMsg];
137	      return { ...c, messages: msgs, title: c.messages.length === 0 ? deriveTitle(text) : c.title };
138	    }));
139	
140	    setIsStreaming(true);
141	    addTelemetry('send', 'user message', text.slice(0, 60));
142	
143	    const ctrl = new AbortController();
144	    abortRef.current = ctrl;
145	    const start = Date.now();
146	
147	    try {
148	      // Build history from current convo messages (exclude the assistant placeholder we just added)
149	      const history = (activeConvo?.messages ?? []).map(m => ({
150	        role: m.role === 'assistant' ? 'assistant' : 'user',
151	        content: m.content,
152	      }));
153	
154	      const res = await fetch('/api/chat', {
155	        method: 'POST',
156	        headers: { 'Content-Type': 'application/json' },
157	        body: JSON.stringify({ user: text.trim(), history }),
158	        signal: ctrl.signal,
159	      });
160	
161	      if (!res.ok || !res.body) {
162	        throw new Error(`HTTP ${res.status}`);
163	      }
164	
165	      const reader = res.body.getReader();
166	      const decoder = new TextDecoder();
167	      let accumulated = '';
168	
169	      while (true) {
170	        const { value, done } = await reader.read();
171	        if (done) break;
172	        const chunk = decoder.decode(value, { stream: true });
173	        // Skip SSE status lines
174	        if (chunk.startsWith('data: ')) continue;
175	        accumulated += chunk;
176	        const snap = accumulated;
177	        setConversations(prev => prev.map(c => {
178	          if (c.id !== activeConvoId) return c;
179	          return {
180	            ...c,
181	            messages: c.messages.map(m =>
182	              m.id === assistantMsgId ? { ...m, content: snap, status: 'streaming' as const } : m
183	            ),
184	          };
185	        }));
186	      }
187	
188	      const elapsed = Date.now() - start;
189	      setConversations(prev => prev.map(c => {
190	        if (c.id !== activeConvoId) return c;
191	        return {
192	          ...c,
193	          messages: c.messages.map(m =>
194	            m.id === assistantMsgId ? { ...m, content: accumulated, status: 'done' as const } : m
195	          ),
196	        };
197	      }));
198	
199	      addTelemetry('response', 'assistant reply', `${elapsed}ms · ${accumulated.length} chars`);
200	    } catch (err: unknown) {
201	      if (err instanceof Error && err.name === 'AbortError') return;
202	      setConversations(prev => prev.map(c => {
203	        if (c.id !== activeConvoId) return c;
204	        return {
205	          ...c,
206	          messages: c.messages.map(m =>
207	            m.id === assistantMsgId ? { ...m, content: 'Something went wrong. Please try again.', status: 'error' as const } : m
208	          ),
209	        };
210	      }));
211	      addTelemetry('error', 'stream failed', String(err));
212	    } finally {
213	      setIsStreaming(false);
214	    }
